import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import "./BusMap.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [loading, setLoading] = useState(true);

  // Smooth position update helper
  const updateBusesSmoothly = (newData) => {
    setBuses((prevBuses) => {
      const updated = newData.map((bus) => {
        const existing = prevBuses.find((b) => b.id === bus.id);
        if (existing) {
          // Smooth transition: interpolate previous position towards new position
          const lat = existing.lat + (bus.lat - existing.lat) * 0.2;
          const lon = existing.lon + (bus.lon - existing.lon) * 0.2;
          return { ...bus, lat, lon };
        }
        return bus;
      });
      return updated;
    });
  };

  const fetchBuses = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/buses");
      const data = await res.json();
      updateBusesSmoothly(data || []);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching buses:", err);
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 5000); // refresh every 5 sec
    return () => clearInterval(interval);
  }, []);

  const getColor = (bus) => {
    if (bus.isAnomaly) return "orange";
    if (bus.isGhost) return "red";
    return "green";
  };

  return (
    <div className="bus-map-container">
      {loading ? (
        <p>Loading buses...</p>
      ) : (
        <MapContainer
          center={[40.7128, -74.006]}
          zoom={12}
          style={{ width: "100vw", height: "100vh" }}
        >
          <TileLayer
            url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
            attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
          />
          {buses.map((bus) => (
            <CircleMarker
              key={bus.id}
              center={[bus.lat, bus.lon]}
              radius={8}
              color={getColor(bus)}
              fillOpacity={0.8}
            >
              <Popup>
                <div>
                  <p><strong>Bus ID:</strong> {bus.id}</p>
                  <p><strong>Status:</strong> {bus.isAnomaly ? "Anomaly" : bus.isGhost ? "Ghost" : "Normal"}</p>
                  {bus.isAnomaly && <p style={{ color: "orange" }}>Anomaly detected!</p>}
                </div>
              </Popup>
            </CircleMarker>
          ))}
        </MapContainer>
      )}
    </div>
  );
}
